from dataclasses import dataclass, field
from typing import Literal

CheckStatus = Literal["pass", "partial", "fail"]

@dataclass
class Check:
    name: str
    weight: float          # sum of all weights in a dimension = 1.0
    status: CheckStatus

    @property
    def score(self) -> float:
        return {"pass": 1.0, "partial": 0.5, "fail": 0.0}[self.status]

    @property
    def weighted_score(self) -> float:
        return self.score * self.weight


@dataclass
class Dimension:
    name: str
    dimension_weight: float   # weight in the overall scorecard
    checks: list[Check]

    @property
    def raw_score(self) -> float:
        return sum(c.weighted_score for c in self.checks) * 100

    @property
    def status(self) -> str:
        if self.raw_score >= 85: return "GREEN"
        if self.raw_score >= 65: return "YELLOW"
        return "RED"


@dataclass
class HealthScorecard:
    system_name: str
    review_date: str
    dimensions: list[Dimension]

    @property
    def overall_score(self) -> float:
        return sum(d.raw_score * d.dimension_weight for d in self.dimensions)

    @property
    def overall_status(self) -> str:
        if self.overall_score >= 85: return "GREEN"
        if self.overall_score >= 65: return "YELLOW"
        return "RED"

    def priority_actions(self) -> list[str]:
        actions = []
        for dim in sorted(self.dimensions, key=lambda d: d.raw_score):
            for check in dim.checks:
                if check.status in ("fail", "partial"):
                    severity = "P1" if check.status == "fail" and dim.name == "Security" else "P2"
                    actions.append(f"[{dim.name}/{severity}] {check.name}: {check.status}")
        return actions[:5]   # top 5 by dimension score (lowest first)

    def print_summary(self) -> None:
        print(f"\n=== {self.system_name} Architecture Health ({self.review_date}) ===")
        for dim in self.dimensions:
            bar = "█" * int(dim.raw_score / 10) + "░" * (10 - int(dim.raw_score / 10))
            print(f"  {dim.name:20s} [{bar}] {dim.raw_score:5.1f}  {dim.status}")
        print(f"  {'OVERALL':20s}  score={self.overall_score:.1f}  {self.overall_status}")
        print("\n  Priority Actions:")
        for i, action in enumerate(self.priority_actions(), 1):
            print(f"    {i}. {action}")
